// kurals 99-200 with tags
const KURALS_99_200 = [
  { number:99, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:10,ta:"இனியவை கூறல்",en:"Utterance of Pleasant Words"}, kural:{line1:"இன்சொல் இனிதீன்றல் காண்பான் எவன்கொலோ",line2:"வன்சொல் வழங்கு வது?"}, meaning:{ta:"இனிய சொற்கள் இன்பம் பயத்தலைக் காண்கின்றவன், அவற்றிற்கு மாறான வன்சொற்களை வழங்குவது என்ன பயன் கருதியோ?",en:"Why does he use harsh words, who sees the pleasure which sweet speech yields?"}, couplet_en:"Who sees the pleasure kindly speech affords, Why makes he use of harsh, repellant words.", transliteration:"Insol Inidheendral Kaanpaan Evankolo Vansol Vazhangu Vadhu", tags:{ta:["இன்சொல்","வன்சொல்","இன்பம்","கடுமை"],en:["sweet speech","harsh speech","pleasure","contrast","kind words"]} },
  { number:100, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:10,ta:"இனியவை கூறல்",en:"Utterance of Pleasant Words"}, kural:{line1:"இனிய உளவாக இன்னாத கூறல்",line2:"கனிஇருப்பக் காய்கவர்ந் தற்று."}, meaning:{ta:"இனிய சொற்கள் இருக்கும் போது அவற்றை விட்டு கடுமையான சொற்களைக் கூறுதல் கனிகள் இருக்கும் போது அவற்றை விட்டு காய்களைப் பறித்துத் தின்பதைப் போன்றது.",en:"To say disagreeable things when agreeable are at hand is like eating unripe fruit when there is ripe."}, couplet_en:"When pleasant words are easy, bitter words to use, Is, leaving sweet ripe fruit, the sour unripe to choose.", transliteration:"Iniya Ulavaaka Innaadha Kooral Kaniiruppak Kaaikavarn Thatru", tags:{ta:["இன்சொல்","கடுஞ்சொல்","உவமை","பழம்"],en:["sweet speech","harsh words","metaphor","fruit","kindness"]} },
  { number:101, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:11,ta:"செய்ந்நன்றி அறிதல்",en:"Gratitude"}, kural:{line1:"செய்யாமல் செய்த உதவிக்கு வையகமும்",line2:"வானகமும் ஆற்றல் அரிது."}, meaning:{ta:"தான் ஓர் உதவியும் முன் செய்யாதிருக்கப் பிறன் தனக்கு செய்த உதவிக்கு மண்ணுலகத்தையும் விண்ணுலகத்தையும் கைமாறாகக் கொடுத்தாலும் ஈடு ஆக முடியாது.",en:"The gift of heaven and earth is not an equivalent for a benefit which is conferred where none had been received."}, couplet_en:"Assistance given by those who ne'er received our aid, Is debt by gift of heaven and earth but poorly paid.", transliteration:"Seyyaamal Seydha Udhavikku Vaiyakamum Vaanakamum Aatral Aridhu", tags:{ta:["நன்றி","உதவி","கைம்மாறு","மதிப்பு"],en:["gratitude","help","repayment","priceless","kindness"]} },
  { number:102, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:11,ta:"செய்ந்நன்றி அறிதல்",en:"Gratitude"}, kural:{line1:"காலத்தி னாற்செய்த நன்றி சிறிதெனினும்",line2:"ஞாலத்தின் மாணப் பெரிது."}, meaning:{ta:"உற்ற காலத்தில் ஒருவன் செய்த உதவி சிறிதளவாக இருந்தாலும், அதன் தன்மையை அறிந்தால் உலகைவிட மிகப் பெரிதாகும்.",en:"A favour conferred in the time of need, though it be small, is in value much larger than the world."}, couplet_en:"A timely benefit, though thing of little worth, The gift itself, in excellence transcends the earth.", transliteration:"Kaalaththi Naarseydha Nandri Siridheninum Gnaalaththin Maanap Peridhu", tags:{ta:["நன்றி","காலம்","உதவி","மதிப்பு"],en:["gratitude","timely help","value","need","kindness"]} },
  { number:103, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:11,ta:"செய்ந்நன்றி அறிதல்",en:"Gratitude"}, kural:{line1:"பயன்தூக்கார் செய்த உதவி நயன்தூக்கின்",line2:"நன்மை கடலின் பெரிது."}, meaning:{ta:"இன்ன பயன் கிடைக்கும் என்று ஆராயாமல் ஒருவன் செய்த உதவியின் அன்புடைமையை ஆராய்ந்தால் அதன் நன்மை கடலைவிட பெரியதாகும்.",en:"If we weigh the excellence of a benefit which is conferred without weighing the return, it is larger than the sea."}, couplet_en:"Kindness shown by those who weigh not what the return may be, When you ponder right its merit, Tis vaster than the sea.", transliteration:"Payandhookkaar Seydha Udhavi Nayandhookkin Nanmai Katalin Peridhu", tags:{ta:["நன்றி","தூய உதவி","கடல்","அன்பு"],en:["gratitude","selfless help","ocean","love","kindness"]} },
  { number:104, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:11,ta:"செய்ந்நன்றி அறிதல்",en:"Gratitude"}, kural:{line1:"தினைத்துணை நன்றி செயினும் பனைத்துணையாக்",line2:"கொள்வர் பயன்தெரி வார்."}, meaning:{ta:"ஒருவன் தினையளவாகிய உதவியைச் செய்த போதிலும் அதன் பயனை ஆராய்கின்றவர், அதனையே பனையளவாகக் கொண்டு போற்றுவர்.",en:"Though the benefit conferred be as small as a millet seed, those who know its advantage will consider it as large as a palmyra fruit."}, couplet_en:"Each benefit to those of actions' fruit who rightly deem, Though small as millet-seed, as palm-tree vast will seem.", transliteration:"Thinaiththunai Nandri Seyinum Panaiththunaiyaak Kolvar Payandheri Vaar", tags:{ta:["நன்றி","சிறுதுணை","மதிப்பு","உதவி"],en:["gratitude","small help","millet","palm","appreciation"]} },
  { number:105, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:11,ta:"செய்ந்நன்றி அறிதல்",en:"Gratitude"}, kural:{line1:"உதவி வரைத்தன்று உதவி உதவி",line2:"செயப்பட்டார் சால்பின் வரைத்து."}, meaning:{ta:"கைமாறாகச் செய்யும் உதவி முன் செய்த உதவியின் அளவை உடையது அன்று, உதவி செய்யப்பட்டவற்றின் பண்புக்கு ஏற்ற அளவை உடையதாகும்.",en:"The benefit itself is not the measure of the benefit; the worth of those who have received it is its measure."}, couplet_en:"The kindly aid's extent is of its worth no measure true; Its worth is as the worth of him to whom the act you do.", transliteration:"Udhavi Varaiththandru Udhavi Udhavi Seyappattaar Saalpin Varaiththu", tags:{ta:["நன்றி","உதவி","பண்பு","அளவு"],en:["gratitude","help","recipient","worth","measure"]} },
  { number:106, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:11,ta:"செய்ந்நன்றி அறிதல்",en:"Gratitude"}, kural:{line1:"மறவற்க மாசற்றார் கேண்மை துறவற்க",line2:"துன்பத்துள் துப்பாயார் நட்பு."}, meaning:{ta:"குற்றமற்றவரின் உறவை எப்போதும் மறக்கலாகாது: துன்பம் வந்த காலத்தில் உறுதுணையாய் உதவியவர்களின் நட்பை எப்போதும் விடலாகாது.",en:"Forsake not the friendship of those who have been your staff in adversity. Forget not the benevolence of the blameless."}, couplet_en:"Kindness of men of stainless soul remember evermore. Forsake thou never friends who were thy stay in sorrow sore.", transliteration:"Maravarka Maasatraar Kenmai Thuravarka Thunpaththul Thuppaayaar Natpu", tags:{ta:["நட்பு","நன்றி","துன்பம்","மறதி"],en:["friendship","gratitude","adversity","loyalty","remember"]} },
  { number:107, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:11,ta:"செய்ந்நன்றி அறிதல்",en:"Gratitude"}, kural:{line1:"எழுமை எழுபிறப்பும் உள்ளுவர் தங்கண்",line2:"விழுமந் துடைத்தவர் நட்பு."}, meaning:{ta:"தம்முடைய துன்பத்தைப் போக்கி உதவியவரின் நட்பைப் பல்வேறு வகையான பிறவியிலும் மறவாமல் போற்றுவர் பெரியோர்.",en:"The wise will remember throughout their seven-fold births the love of those who have wiped away their affliction."}, couplet_en:"Through all seven worlds, in seven-fold birth, Remains in memory of the wise. Friendship of those who wiped on earth, The tears of sorrow from their eyes.", transliteration:"Ezhumai Ezhupirappum Ulluvar Thangan Vizhuman Thutaiththavar Natpu", tags:{ta:["நட்பு","நன்றி","பிறவி","துன்பம்"],en:["friendship","gratitude","seven births","adversity","memory"]} },
  { number:108, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:11,ta:"செய்ந்நன்றி அறிதல்",en:"Gratitude"}, kural:{line1:"நன்றி மறப்பது நன்றன்று நன்றல்லது",line2:"அன்றே மறப்பது நன்று."}, meaning:{ta:"ஒருவர் முன் செய்த நன்மையை மறப்பது அறம் அன்று; அவர் செய்த தீமையைச் செய்த அப்பொழுதே மறந்து விடுவது அறம்.",en:"It is not good to forget a benefit; it is good to forget an injury even in the very moment it is inflicted."}, couplet_en:"Tis never good to let the thought of good things done thee pass away; Of things not good, tis good to rid thy memory that very day.", transliteration:"Nandri Marappadhu Nandrandru Nandralladhu Andre Marappadhu Nandru", tags:{ta:["நன்றி","மன்னிப்பு","மறதி","அறம்"],en:["gratitude","forgiveness","memory","virtue","kindness"]} },
  { number:109, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:11,ta:"செய்ந்நன்றி அறிதல்",en:"Gratitude"}, kural:{line1:"கொன்றன்ன இன்னா செயினும் அவர்செய்த",line2:"ஒன்றுநன்று உள்ளக் கெடும்."}, meaning:{ta:"முன் உதவி செய்தவர் பின்பு கொன்றார் போன்ற துன்பத்தைச் செய்தாரானாலும், அவர் முன் செய்த ஒரு நன்மையை நினைத்தாலும் அந்தத் துன்பம் கெடும்.",en:"Though one inflict an injury great as murder, it will perish before the thought of one benefit formerly conferred."}, couplet_en:"Effaced straightway is deadliest injury, By thought of one kind act in days gone by.", transliteration:"Kondranna Innaa Seyinum Avarseydha Ondrunandru Ullak Ketum", tags:{ta:["நன்றி","மன்னிப்பு","நன்மை","தீமை"],en:["gratitude","forgiveness","past kindness","injury","virtue"]} },
  { number:110, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:11,ta:"செய்ந்நன்றி அறிதல்",en:"Gratitude"}, kural:{line1:"எந்நன்றி கொன்றார்க்கும் உய்வுண்டாம் உய்வில்லை",line2:"செய்ந்நன்றி கொன்ற மகற்கு."}, meaning:{ta:"எந்த அறத்தை அழித்தவர்க்கும் தப்பிப் பிழைக்க வழி உண்டாகும்; ஒருவர் செய்த உதவியை மறந்து அழித்தவனுக்கு உய்வு இல்லை.",en:"He who has killed every virtue may yet escape; there is no escape for him who has killed a benefit."}, couplet_en:"Who every good have killed, may yet destruction flee; Who benefit has killed, that man shall ne'er scape free.", transliteration:"Ennandri Kondraarkkum Uyvuntaam Uyvillai Seynnandri Kondra Makarku", tags:{ta:["நன்றி","நன்றியின்மை","தண்டனை","அறம்"],en:["gratitude","ingratitude","punishment","escape","virtue"]} },
  { number:111, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:12,ta:"நடுவு நிலைமை",en:"Impartiality"}, kural:{line1:"தகுதி எனவொன்று நன்றே பகுதியால்",line2:"பாற்பட்டு ஒழுகப் பெறின்."}, meaning:{ta:"அந்தந்தப் பகுதிதோறும் முறையோடு பொருந்தி ஒழுகப்பெற்றால், நடுவுநிலைமை என்று கூறப்படும் அறம் நன்மையாகும்.",en:"That equity which consists in acting with equal regard to each of the three divisions of men is a pre-eminent virtue."}, couplet_en:"If justice, failing not, its quality maintain, Giving to each his due, tis man's one highest gain.", transliteration:"Thakudhi Enavondru Nandre Pakudhiyaal Paarpattu Ozhukap Perin", tags:{ta:["நடுவுநிலை","நீதி","அறம்","சமத்துவம்"],en:["impartiality","justice","equity","fairness","virtue"]} },
  { number:112, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:12,ta:"நடுவு நிலைமை",en:"Impartiality"}, kural:{line1:"செப்பம் உடையவன் ஆக்கஞ் சிதைவின்றி",line2:"எச்சத்திற் கேமாப்பு உடைத்து."}, meaning:{ta:"நடுவுநிலைமை உடையவனின் செல்வவளம் அழிவில்லாமல் அவனுடைய வழியில் உள்ளார்க்கும் உறுதியான நன்மை தருவதாகும்.",en:"The wealth of the man of rectitude will not perish, but will bring happiness also to his posterity."}, couplet_en:"The just man's wealth unwasting shall endure, And to his race a lasting joy ensure.", transliteration:"Seppam Utaiyavan Aakkanj Chidhaivindri Echchaththir Kemaappu Utaiththu", tags:{ta:["நடுவுநிலை","செல்வம்","வழிமரபு","நீதி"],en:["impartiality","wealth","posterity","justice","fairness"]} },
  { number:113, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:12,ta:"நடுவு நிலைமை",en:"Impartiality"}, kural:{line1:"நன்றே தரினும் நடுவிகந்தாம் ஆக்கத்தை",line2:"அன்றே யொழிய விடல்."}, meaning:{ta:"தீமை பயக்காமல் நன்மையே தருவதானாலும் நடுவுநிலைமை தவறி உண்டாகும் ஆக்கத்தை அப்போதே கைவிட வேண்டும்.",en:"Forsake in the very moment of acquisition that gain which, though it should bring advantage, is without equity."}, couplet_en:"Though only good it seem to give, yet gain By wrong acquired, not e'en one day retain.", transliteration:"Nandre Tharinum Natuvikandhaam Aakkaththai Andre Yozhiya Vital", tags:{ta:["நடுவுநிலை","நீதி","ஆக்கம்","அறம்"],en:["impartiality","unjust gain","justice","abandon","virtue"]} },
  { number:114, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:12,ta:"நடுவு நிலைமை",en:"Impartiality"}, kural:{line1:"தக்கார் தகவிலர் என்பது அவரவர்",line2:"எச்சத்தாற் காணப்ப படும்."}, meaning:{ta:"நடுவுநிலைமை உடையவர் நடுவுநிலைமை இல்லாதவர் என்பது அவரவர்க்குப் பின் எஞ்சி நிற்கும் புகழாலும் பழியாலும் காணப்படும்.",en:"The worthy and unworthy may be known by the existence or otherwise of good offsprings."}, couplet_en:"Who just or unjust lived shall soon appear: By each one's offspring shall the truth be clear.", transliteration:"Thakkaar Thakavilar Enpadhu Avaravar Echchaththaar Kaanap Patum", tags:{ta:["நடுவுநிலை","புகழ்","வழிமரபு","நீதி"],en:["impartiality","posterity","fame","justice","legacy"]} },
  { number:115, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:12,ta:"நடுவு நிலைமை",en:"Impartiality"}, kural:{line1:"கேடும் பெருக்கமும் இல்லல்ல நெஞ்சத்துக்",line2:"கோடாமை சான்றோர்க் கணி."}, meaning:{ta:"கேடும் ஆக்கமும் வாழ்வில் இல்லாதவை அல்ல; ஆகையால் நெஞ்சில் நடுவுநிலைமை தவறாமல் இருத்தலே சான்றோர்க்கு அழகாகும்.",en:"Loss and gain come not without cause; it is the ornament of the wise to preserve evenness of mind under both."}, couplet_en:"The gain and loss in life are not mere accident; Just mind inflexible is sages' ornament.", transliteration:"Ketum Perukkamum Illalla Nenjaththuk Kotaamai Saandrork Kani", tags:{ta:["நடுவுநிலை","சான்றோர்","மனம்","சமத்துவம்"],en:["impartiality","equanimity","wise men","mind","ornament"]} },
  { number:116, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:12,ta:"நடுவு நிலைமை",en:"Impartiality"}, kural:{line1:"கெடுவல்யான் என்பது அறிகதன் நெஞ்சம்",line2:"நடுவொரீஇ அல்ல செயின்."}, meaning:{ta:"தன் நெஞ்சம் நடுவுநிலை நீங்கித் தவறு செய்ய நினைக்குமாயின், நான் கெடப்போகின்றேன் என்று ஒருவன் அறிய வேண்டும்.",en:"Let him whose mind departing from equity commits sin well consider within himself, I shall perish."}, couplet_en:"If, right deserting, heart to evil turn, Let man impending ruin's sign discern.", transliteration:"Ketuvalyaan Enpadhu Arikadhan Nenjam Natuvoreei Alla Seyin", tags:{ta:["நடுவுநிலை","சினம்","அழிவு","நெஞ்சு"],en:["impartiality","ruin","sin","mind","warning"]} },
  { number:117, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:12,ta:"நடுவு நிலைமை",en:"Impartiality"}, kural:{line1:"கெடுவாக வையாது உலகம் நடுவாக",line2:"நன்றிக்கண் தங்கியான் தாழ்வு."}, meaning:{ta:"நடுவுநிலைமை நின்று அறநெறியில் நிலைத்து வாழகின்றவன் அடைந்த வறுமை நிலையைக் கேடு என கொள்ளாது உலகு.",en:"The great will not regard as poverty the low estate of that man who dwells in the virtue of equity."}, couplet_en:"The man who justly lives, tenacious of the right, In low estate is never low to wise man's sight.", transliteration:"Keduvaaka Vaiyaadhu Ulakam Naduvaaka Nandrikkan Thangiyaan Thaazhvu", tags:{ta:["நடுவுநிலை","வறுமை","உயர்வு","அறம்"],en:["impartiality","poverty","greatness","virtue","justice"]} },
  { number:118, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:12,ta:"நடுவு நிலைமை",en:"Impartiality"}, kural:{line1:"சமன்செய்து சீர்தூக்குங் கோல்போல் அமைந்தொருபால்",line2:"கோடாமை சான்றோர்க் கணி."}, meaning:{ta:"முன்னே தான் சமமாக இருந்து, பின்பு பொருளைச் சீர்தூக்கும் துலாக்கோல் போல் அமைந்து, ஒரு பக்கமாக சாயாமல் நடுவுநிலைமை போற்றுவது சான்றோர்க்கு அழகாகும்.",en:"To incline to neither side, but to rest impartial as the even-fixed scale is the ornament of the wise."}, couplet_en:"To stand, like balance-rod that level hangs and rightly weighs, With calm unbiassed equity of soul, is sages' praise.", transliteration:"Samanseydhu Seerdhookkung Kolpol Amaindhorupaal Kotaamai Saandrork Kani", tags:{ta:["நடுவுநிலை","தராசு","சான்றோர்","நீதி"],en:["impartiality","balance","scale","wise","justice"]} },
  { number:119, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:12,ta:"நடுவு நிலைமை",en:"Impartiality"}, kural:{line1:"சொற்கோட்டம் இல்லது செப்பம் ஒருதலையா",line2:"உட்கோட்டம் இன்மை பெறின்."}, meaning:{ta:"உள்ளத்தில் கோணுதல் இல்லாத தன்மையை உறுதியாகப் பெற்றால், சொல்லிலும் கோணுதல் இல்லாதிருத்தல் நடுவுநிலைமையாம்.",en:"Freedom from obliquity of speech is rectitude, if there be corresponding freedom from bias of mind."}, couplet_en:"Inflexibility in word is righteousness, If men inflexibility of soul possess.", transliteration:"Sorkottam Illadhu Seppam Orudhalaiyaa Utkottam Inmai Perin", tags:{ta:["நடுவுநிலை","சொல்","மனம்","உண்மை"],en:["impartiality","speech","mind","truth","rectitude"]} },
  { number:120, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:12,ta:"நடுவு நிலைமை",en:"Impartiality"}, kural:{line1:"வாணிகம் செய்வார்க்கு வாணிகம் பேணிப்",line2:"பிறவும் தமபோல் செயின்."}, meaning:{ta:"பிறர் பொருளையும் தம் பொருள் போல் போற்றிச் செய்தால், அதுவே வாணிகம் செய்வோர்க்கு உரிய நல்ல வாணிக முறையாகும்.",en:"The true merchandize of merchants is to guard and do by the things of others as they do by their own."}, couplet_en:"As thriving trader is the trader known, Who guards another's interests as his own.", transliteration:"Vaanikam Seyvaarkku Vaanikam Penip Piravum Thamapol Seyin", tags:{ta:["வாணிகம்","நடுவுநிலை","நேர்மை","வியாபாரம்"],en:["trade","impartiality","honesty","commerce","justice"]} },
  { number:121, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:13,ta:"அடக்கமுடைமை",en:"Self-restraint"}, kural:{line1:"அடக்கம் அமரருள் உய்க்கும் அடங்காமை",line2:"ஆரிருள் உய்த்து விடும்."}, meaning:{ta:"அடக்கம் ஒருவனை உயர்த்தித் தேவருள் சேர்க்கும்; அடக்கம் இல்லாதிருத்தல், பொல்லாத இருள் போன்ற தீய வாழ்க்கையில் செலுத்தி விடும்.",en:"Self-control will place a man among the Gods; the want of it will drive him into the thickest darkness of hell."}, couplet_en:"Control of self does man conduct to bliss th' immortals share; Indulgence leads to deepest night, and leaves him there.", transliteration:"Atakkam Amararul Uykkum Atangaamai Aarirul Uyththu Vitum", tags:{ta:["அடக்கம்","தேவர்","இருள்","ஒழுக்கம்"],en:["self-restraint","heaven","darkness","discipline","virtue"]} },
  { number:122, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:13,ta:"அடக்கமுடைமை",en:"Self-restraint"}, kural:{line1:"காக்க பொருளா அடக்கத்தை ஆக்கம்",line2:"அதனினூஉங் கில்லை உயிர்க்கு."}, meaning:{ta:"அடக்கத்தை உறுதிப் பொருளாகக் கொண்டு போற்றிக் காக்க வேண்டும். அந்த அடக்கத்தைவிட மேம்பட்ட ஆக்கம் உயிர்க்கு இல்லை.",en:"Let self-control be guarded as a treasure; there is no greater source of good for man than that."}, couplet_en:"Guard thou as wealth the power of self-control; Than this no greater gain to living soul.", transliteration:"Kaakka Porulaa Atakkaththai Aakkam Adhaninooung Killai Uyirkku", tags:{ta:["அடக்கம்","செல்வம்","காவல்","ஒழுக்கம்"],en:["self-restraint","treasure","wealth","discipline","virtue"]} },
  { number:123, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:13,ta:"அடக்கமுடைமை",en:"Self-restraint"}, kural:{line1:"செறிவறிந்து சீர்மை பயக்கும் அறிவறிந்து",line2:"ஆற்றின் அடங்கப் பெறின்."}, meaning:{ta:"அறிய வேண்டியவற்றை அறிந்து, நல்வழியில் அடங்கி ஒழுகப்பெற்றால், அந்த அடக்கம் நல்லோரால் அறியப்பட்டு மேன்மை பயக்கும்.",en:"Knowing that self-control is knowledge, if a man should control himself, such self-control will bring him distinction among the wise."}, couplet_en:"If versed in wisdom's lore by virtue's law you self restrain, Your self-repression known will yield you glory's gain.", transliteration:"Serivarindhu Seermai Payakkum Arivarindhu Aatrin Atangap Perin", tags:{ta:["அடக்கம்","அறிவு","புகழ்","ஒழுக்கம்"],en:["self-restraint","knowledge","fame","wisdom","discipline"]} },
  { number:124, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:13,ta:"அடக்கமுடைமை",en:"Self-restraint"}, kural:{line1:"நிலையின் திரியாது அடங்கியான் தோற்றம்",line2:"மலையினும் மாணப் பெரிது."}, meaning:{ta:"தன் நிலையிலிருந்து மாறுபடாமல் அடங்கி ஒழுகுவோனுடைய உயர்வு, மலையின் உயர்வை விட மிகவும் பெரிதாகும்.",en:"More lofty than a mountain will be the greatness of that man who without swerving from his domestic state, controls himself."}, couplet_en:"In his station, all unswerving, if man self subdue, Greater he than mountain proudly rising to the view.", transliteration:"Nilaiyin Thiriyaadhu Atangiyaan Thotram Malaiyinum Maanap Peridhu", tags:{ta:["அடக்கம்","மலை","உயர்வு","உறுதி"],en:["self-restraint","mountain","greatness","steadfast","discipline"]} },
  { number:125, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:13,ta:"அடக்கமுடைமை",en:"Self-restraint"}, kural:{line1:"எல்லார்க்கும் நன்றாம் பணிதல் அவருள்ளும்",line2:"செல்வர்க்கே செல்வம் தகைத்து."}, meaning:{ta:"பணிவுடையவராக ஒழுகுதல் பொதுவாக எல்லோர்க்கும் நல்லதாகும்; அவர்களுள் சிறப்பாகச் செல்வர்க்கே மற்றொரு செல்வம் போன்றதாகும்.",en:"Humility is good in all; but especially in the rich it is the excellence of higher riches."}, couplet_en:"To all humility is goodly grace; but chief to them With fortune blessed, tis fortune's diadem.", transliteration:"Ellaarkkum Nandraam Panidhal Avarullum Selvarkke Selvam Thakaiththu", tags:{ta:["பணிவு","அடக்கம்","செல்வர்","சிறப்பு"],en:["humility","self-restraint","wealth","grace","virtue"]} },
  { number:126, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:13,ta:"அடக்கமுடைமை",en:"Self-restraint"}, kural:{line1:"ஒருநம்யுள் ஆமைபோல் ஐந்தடக்கல் ஆற்றின்",line2:"எழுநம்யும் ஏமாப் புடைத்து."}, meaning:{ta:"ஒரு பிறப்பில், ஆமைபோல் ஐம்பொறிகளையும் அடக்கியாள வல்லவனானால், அஃது அவனுக்குப் பல பிறப்பிலும் காப்பாகும் சிறப்பு உடையது.",en:"Should one throughout a single birth, like a tortoise keep in his five senses, the fruit of it will prove a safe-guard throughout the seven-fold births."}, couplet_en:"Like tortoise, who the five restrains In one, through seven world bliss obtains.", transliteration:"Orumaiyul Aamaipol Aindhatakkal Aatrin Ezhumaiyum Emaap Putaiththu", tags:{ta:["அடக்கம்","ஆமை","புலன்கள்","பிறவி"],en:["self-restraint","tortoise","senses","seven births","protection"]} },
  { number:127, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:13,ta:"அடக்கமுடைமை",en:"Self-restraint"}, kural:{line1:"யாகாவா ராயினும் நாகாக்க காவாக்கால்",line2:"சோகாப்பர் சொல்லிழுக்குப் பட்டு."}, meaning:{ta:"காக்க வேண்டியவற்றுள் எவற்றைக் காக்காவிட்டாலும் நாவையாவது காக்க வேண்டும்; காக்கத் தவறினால் சொற்குற்றத்தில் அகப்பட்டுத் துன்புறுவர்.",en:"Whatever besides you leave unguarded, guard your tongue; otherwise errors of speech and the consequent misery will ensue."}, couplet_en:"Whate'er they fail to guard, o'er lips men guard should keep; If not, through fault of tongue, they bitter tears shall weep.", transliteration:"Yaakaavaa Raayinum Naakaakka Kaavaakkaal Sokaappar Sollizhukkup Pattu", tags:{ta:["நா","அடக்கம்","சொல்","குற்றம்"],en:["tongue","self-restraint","speech","fault","guard"]} },
  { number:128, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:13,ta:"அடக்கமுடைமை",en:"Self-restraint"}, kural:{line1:"ஒன்றானுந் தீச்சொல் பொருட்பயன் உண்டாயின்",line2:"நன்றாகா தாகி விடும்."}, meaning:{ta:"தீய சொற்களின் பொருளால் விளையும் தீமை ஒன்றாயினும் ஒருவனிடம் உண்டானால், அதனால் மற்ற அறங்களாலும் நன்மை விளையாமல் போகும்.",en:"If a man's speech be productive of a single evil, all the good by him will be turned into evil."}, couplet_en:"Though some small gain of good it seem to bring, The evil word is parent still of evil thing.", transliteration:"Ondraanun Theechchol Porutpayan Untaayin Nandraakaa Thaaki Vitum", tags:{ta:["கடுஞ்சொல்","அடக்கம்","தீமை","சொல்"],en:["evil speech","self-restraint","harm","tongue","virtue"]} },
  { number:129, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:13,ta:"அடக்கமுடைமை",en:"Self-restraint"}, kural:{line1:"தீயினாற் சுட்டபுண் உள்ளாறும் ஆறாதே",line2:"நாவினாற் சுட்ட வடு."}, meaning:{ta:"தீயினால் சுட்ட புண் புறத்தே வடு இருந்தாலும் உள்ளே ஆறிவிடும்; ஆனால் நாவினால் தீய சொல் கூறிச் சுடும் வடு என்றும் ஆறாது.",en:"The wound which has been burnt in by fire may heal, but a wound burnt in by the tongue will never heal."}, couplet_en:"In flesh by fire inflamed, nature may thoroughly heal the sore; In soul by tongue inflamed, the ulcer healeth never more.", transliteration:"Theeyinaar Suttapun Ullaarum Aaraadhe Naavinaar Sutta Vatu", tags:{ta:["நாவினால் காயம்","வன்சொல்","ஆறாத புண்","சொல்"],en:["tongue","words wound","fire burn","heals","harsh speech"]} },
  { number:130, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:13,ta:"அடக்கமுடைமை",en:"Self-restraint"}, kural:{line1:"கதங்காத்துக் கற்றடங்கல் ஆற்றுவான் செவ்வி",line2:"அறம்பார்க்கும் ஆற்றின் நுழைந்து."}, meaning:{ta:"சினம் தோன்றாமல் காத்து, கல்வி கற்று, அடக்கமுடையவனாக இருக்க வல்லவனுடைய செவ்வியை, அவனுடைய வழியில் சென்று அறம் பார்த்திருக்கும்.",en:"Virtue, seeking for an opportunity, will come into the path of that man who, possessed of learning and self-control, guards himself against anger."}, couplet_en:"Who learns restraint, and guards his soul from wrath, Virtue, a timely aid, attends his path.", transliteration:"Kadhangaaththuk Katratangal Aatruvaan Sevvi Arampaarkkum Aatrin Nuzhaindhu", tags:{ta:["அடக்கம்","கோபம்","கல்வி","அறம்"],en:["self-restraint","anger","learning","virtue","discipline"]} },
  { number:131, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:14,ta:"ஒழுக்கமுடைமை",en:"Decorum"}, kural:{line1:"ஒழுக்கம் விழுப்பந் தரலான் ஒழுக்கம்",line2:"உயிரினும் ஓம்பப் படும்."}, meaning:{ta:"ஒழுக்கமே எல்லார்க்கும் மேன்மையைத் தருவதாக இருப்பதால், அந்த ஒழுக்கமே உயிரை விடச் சிறந்ததாகப் போற்றப்படும்.",en:"Propriety of conduct leads to eminence; it should therefore be preserved more carefully than life."}, couplet_en:"Decorum gives especial excellence; with greater care Decorum should men guard than life, which all men share.", transliteration:"Ozhukkam Vizhuppan Tharalaan Ozhukkam Uyirinum Ompap Patum", tags:{ta:["ஒழுக்கம்","உயிர்","மேன்மை","சிறப்பு"],en:["decorum","life","eminence","conduct","virtue"]} },
  { number:132, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:14,ta:"ஒழுக்கமுடைமை",en:"Decorum"}, kural:{line1:"பரிந்தோம்பிக் காக்க ஒழுக்கம் தெரிந்தோம்பித்",line2:"தேரினும் அஃதே துணை."}, meaning:{ta:"ஒழுக்கத்தை வருந்தியும் போற்றிக் காக்க வேண்டும்; பலவற்றையும் ஆராய்ந்து போற்றித் தெளிந்தாலும், அந்த ஒழுக்கமே வாழ்க்கையில் துணையாக விளங்கும்.",en:"Let propriety of conduct be laboriously preserved and guarded; though one know and practise and excel in many virtues, that will be an eminent aid."}, couplet_en:"Searching, duly watching, learning, decorum still we find; Man's only aid; toiling, guard thou this with watchful mind.", transliteration:"Parindhompik Kaakka Ozhukkam Therindhompith Therinum Aqdhe Thunai", tags:{ta:["ஒழுக்கம்","காவல்","துணை","வாழ்வு"],en:["decorum","guard","support","life","virtue"]} },
  { number:133, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:14,ta:"ஒழுக்கமுடைமை",en:"Decorum"}, kural:{line1:"ஒழுக்கம் உடைமை குடிமை இழுக்கம்",line2:"இழிந்த பிறப்பாய் விடும்."}, meaning:{ta:"ஒழுக்கம் உடையவராக வாழ்வதே உயர்ந்த குடிப்பிறப்பின் தன்மையாகும்; ஒழுக்கம் தவறுதல் இழிந்த குடிப்பிறப்பின் தன்மையாகி விடும்.",en:"Propriety of conduct is true greatness of birth, and impropriety will sink into a mean birth."}, couplet_en:"Decorum's true nobility on earth; Indecorum's issue is ignoble birth.", transliteration:"Ozhukkam Utaimai Kutimai Izhukkam Izhindha Pirappaai Vitum", tags:{ta:["ஒழுக்கம்","குடிமை","பிறப்பு","தகுதி"],en:["decorum","nobility","birth","conduct","virtue"]} },
  { number:134, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:14,ta:"ஒழுக்கமுடைமை",en:"Decorum"}, kural:{line1:"மறப்பினும் ஓத்துக் கொளலாகும் பார்ப்பான்",line2:"பிறப்பொழுக்கங் குன்றக் கெடும்."}, meaning:{ta:"கற்ற மறைப் பொருளை மறந்தாலும் மீண்டும் அதனை ஓதிக் கற்றுக் கொள்ள முடியும்; ஆனால் மறை ஓதுவனுடைய குடிப்பிறப்பு, ஒழுக்கம் குன்றினால் கெடும்.",en:"A Brahman though he should forget the Vedas may recover it by reading; but, if he fail in propriety of conduct even his high birth will be destroyed."}, couplet_en:"Though he forget, the Brahman may regain his Vedic lore; Failing in decorum due, birthright's gone for evermore.", transliteration:"Marappinum Oththuk Kolalaakum Paarppaan Pirappozhukkang Kundrak Ketum", tags:{ta:["ஒழுக்கம்","கல்வி","பிறப்பு","குடிமை"],en:["decorum","learning","birth","conduct","nobility"]} },
  { number:135, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:14,ta:"ஒழுக்கமுடைமை",en:"Decorum"}, kural:{line1:"அழுக்கா றுடையான்கண் ஆக்கம்போன்று இல்லை",line2:"ஒழுக்க மிலான்கண் உயர்வு."}, meaning:{ta:"பொறாமை உடையவனிடத்தில் ஆக்கம் இல்லாதவாறு போல, ஒழுக்கம் இல்லாதவனுடைய வாழ்க்கையில் உயர்வு இல்லையாகும்.",en:"Just as the envious man will be without wealth, so will the man destitute of propriety of conduct be without greatness."}, couplet_en:"The envious soul in life no rich increase of blessing gains, So man of due decorum void no dignity obtains.", transliteration:"Azhukkaa Rutaiyaankan Aakkampondru Illai Ozhukka Milaankan Uyarvu", tags:{ta:["ஒழுக்கம்","பொறாமை","உயர்வு","தகுதி"],en:["decorum","envy","greatness","conduct","virtue"]} },
  { number:136, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:14,ta:"ஒழுக்கமுடைமை",en:"Decorum"}, kural:{line1:"ஒழுக்கத்தின் ஒல்கார் உரவோர் இழுக்கத்தின்",line2:"ஏதம் படுபாக் கறிந்து."}, meaning:{ta:"ஒழுக்கம் தவறுதலால் குற்றம் உண்டாவதை அறிந்து, மனவலிமை உடைய சான்றோர் ஒழுக்கத்தில் தவறாமல் காத்துக் கொள்வர்.",en:"Those firm in mind will not slacken in their observance of the proprieties of life, knowing, as they do, the misery that flows from the transgression from them."}, couplet_en:"The strong of soul no jot abate of strict decorum's laws, Knowing that due decorum's breach foulest disgrace will cause.", transliteration:"Ozhukkaththin Olkaar Uravor Izhukkaththin Edham Patupaak Karindhu", tags:{ta:["ஒழுக்கம்","உரவோர்","குற்றம்","உறுதி"],en:["decorum","steadfast","disgrace","strong mind","virtue"]} },
  { number:137, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:14,ta:"ஒழுக்கமுடைமை",en:"Decorum"}, kural:{line1:"ஒழுக்கத்தின் எய்துவர் மேன்மை இழுக்கத்தின்",line2:"எய்துவர் எய்தாப் பழி."}, meaning:{ta:"ஒழுக்கத்தால் எவரும் மேம்பாட்டை அடைவர்; ஒழுக்கத்திலிருந்து தவறுதலால் அடையத் தகாத பெரும் பழியை அடைவர்.",en:"From propriety of conduct men obtain greatness; from impropriety comes insufferable disgrace."}, couplet_en:"Tis source of dignity when true decorum is preserved; Who break decorum's rules endure e'en censures undeserved.", transliteration:"Ozhukkaththin Eydhuvar Menmai Izhukkaththin Eydhuvar Eydhaap Pazhi", tags:{ta:["ஒழுக்கம்","மேன்மை","பழி","சிறப்பு"],en:["decorum","greatness","disgrace","conduct","virtue"]} },
  { number:138, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:14,ta:"ஒழுக்கமுடைமை",en:"Decorum"}, kural:{line1:"நன்றிக்கு வித்தாகும் நல்லொழுக்கம் தீயொழுக்கம்",line2:"என்றும் இடும்பை தரும்."}, meaning:{ta:"நல்லொழுக்கம் இன்பமான நல்வாழ்க்கைக்குக் காரணமாக இருக்கும்; தீயொழுக்கம் எப்போதும் துன்பத்தைக் கொடுக்கும்.",en:"Propriety of conduct is the seed of virtue; impropriety will ever cause sorrow."}, couplet_en:"Decorum true observed a seed of good will be; Decorum's breach will sorrow yield eternally.", transliteration:"Nandrikku Viththaakum Nallozhukkam Theeyozhukkam Endrum Itumpai Tharum", tags:{ta:["ஒழுக்கம்","தீவொழுக்கம்","துன்பம்","விதை"],en:["good conduct","bad conduct","sorrow","seed","virtue"]} },
  { number:139, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:14,ta:"ஒழுக்கமுடைமை",en:"Decorum"}, kural:{line1:"ஒழுக்க முடையவர்க்கு ஒல்லாவே தீய",line2:"வழுக்கியும் வாயாற் சொலல்."}, meaning:{ta:"தீய சொற்களைத் தவறியும் தம்முடைய வாயால் சொல்லும் குற்றம், ஒழுக்கம் உடையவர்க்கு பொருந்தாததாகும்.",en:"Those who study propriety of conduct will not speak evil, even forgetfully."}, couplet_en:"It cannot be that they who strict decorum's law fulfil, E'en in forgetful mood, should utter words of ill.", transliteration:"Ozhukka Mutaiyavarkku Ollaave Theeya Vazhukkiyum Vaayaar Solal", tags:{ta:["ஒழுக்கம்","சொல்","கடுஞ்சொல்","நல்லோர்"],en:["decorum","speech","evil words","good conduct","virtue"]} },
  { number:140, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:14,ta:"ஒழுக்கமுடைமை",en:"Decorum"}, kural:{line1:"உலகத்தோடு ஒட்ட ஒழுகல் பலகற்றும்",line2:"கல்லார் அறிவிலா தார்"}, meaning:{ta:"உலகத்து உயர்ந்தவரோடு பொருந்த ஒழுகும் முறையைக் கற்காதவர், பல நூல்களைக் கற்றிருந்த போதிலும் அறிவில்லாதவரே ஆவர்.",en:"Those who know not how to act agreeably to the world, though they have learnt many things, are still ignorant."}, couplet_en:"Who know not with the world in harmony to dwell, May many things have learned, but nothing well.", transliteration:"Ulakaththotu Otta Ozhukal Palakatrum Kallaar Arivilaa Thaar", tags:{ta:["ஒழுக்கம்","கல்வி","உலகம்","அறியாமை"],en:["decorum","learning","world","ignorance","wisdom"]} },
  { number:141, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:15,ta:"பிறனில் விழையாமை",en:"Not Coveting Another's Wife"}, kural:{line1:"பிறன்பொருளாள் பெட்டொழுகும் பேதைமை ஞாலத்து",line2:"அறம்பொருள் கண்டார்கண் இல்."}, meaning:{ta:"பிறனுடைய உரிமையாகிய மனைவியை விரும்பி நடக்கும் அறியாமை, உலகத்தில் அறமும் பொருளும் ஆராய்ந்து கண்டவரிடம் இல்லை.",en:"The folly of desiring her who is the property of another will not be found in those who know the attributes of virtue and the rights of property."}, couplet_en:"Who laws of virtue and possession's rights have known, Indulge no foolish love of her by right another's own.", transliteration:"Piranporulaal Pettozhukum Pedhaimai Gnaalaththu Aramporul Kantaarkan Il", tags:{ta:["கற்பு","அடுத்தவன் மனைவி","அறம்","மூடம்"],en:["chastity","another's wife","virtue","folly","ethics"]} },
  { number:142, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:15,ta:"பிறனில் விழையாமை",en:"Not Coveting Another's Wife"}, kural:{line1:"அறன்கடை நின்றாருள் எல்லாம் பிறன்கடை",line2:"நின்றாரின் பேதையார் இல்."}, meaning:{ta:"அறத்தை விட்டுத் தீநெறியில் நின்றவர் எல்லாரிலும் பிறன் மனைவியை விரும்பி அவனுடைய வாயிலில் சென்று நின்றவரைப் போல் அறிவிலிகள் இல்லை.",en:"Among all those who stand on the outside of virtue, there are no greater fools than those who stand outside their neighbour's door."}, couplet_en:"No fools, of all that stand from virtue's pale shut out, Like those who longing lurk their neighbour's gate without.", transliteration:"Arankatai Nindraarul Ellaam Pirankatai Nindraarin Pedhaiyaar Il", tags:{ta:["அடுத்தவன் மனைவி","மூடம்","அறம்","பழி"],en:["another's wife","folly","virtue","disgrace","sin"]} },
  { number:143, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:15,ta:"பிறனில் விழையாமை",en:"Not Coveting Another's Wife"}, kural:{line1:"விளிந்தாரின் வேறல்லர் மன்ற தெளிந்தாரில்",line2:"தீமை புரிந்து ஒழுகு வார்."}, meaning:{ta:"ஐயமில்லாமல் தெளிந்து நம்பியவருடைய மனைவியிடத்தே விருப்பம் கொண்டு தீமையைச் செய்து நடப்பவர், செத்தவரை விட வேறுபட்டவர் அல்லர்.",en:"Certainly they are no better than dead men who desire evil towards the wife of those who undoubtingly confide in them."}, couplet_en:"They're numbered with the dead, e'en while they live, how otherwise? With wife of sure confiding friend who evil things devise.", transliteration:"Vilindhaarin Verallar Mandra Thelindhaaril Theemai Purindhu Ozhuku Vaar", tags:{ta:["நட்பு","நம்பிக்கை","கற்பு","துரோகம்"],en:["friendship","betrayal","another's wife","trust","sin"]} },
  { number:144, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:15,ta:"பிறனில் விழையாமை",en:"Not Coveting Another's Wife"}, kural:{line1:"எனைத்துணையர் ஆயினும் என்னாம் தினைத்துணையும்",line2:"தேரான் பிறனில் புகல்."}, meaning:{ta:"தினையளவும் ஆராய்ந்து பார்க்காமல் பிறனுடைய மனைவியிடம் செல்லுதல், எவ்வளவு பெருமையை உடையவராயினும் என்னவாக முடியும்?",en:"However great one may be, what does it avail if, without at all considering his guilt, he goes unto the wife of another?"}, couplet_en:"How great soe'er they be, what gain have they of life, Who, not a whit reflecting, seek a neighbour's wife.", transliteration:"Enaiththunaiyar Aayinum Ennaam Thinaiththunaiyum Theraan Piranil Pukal", tags:{ta:["அடுத்தவன் மனைவி","பெருமை","குற்றம்","அறம்"],en:["another's wife","greatness","guilt","sin","reflection"]} },
  { number:145, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:15,ta:"பிறனில் விழையாமை",en:"Not Coveting Another's Wife"}, kural:{line1:"எளிதென இல்லிறப்பான் எய்துமெஞ் ஞான்றும்",line2:"விளியாது நிற்கும் பழி."}, meaning:{ta:"இச்செயல் எளியது என எண்ணிப் பிறனுடைய மனைவியிடம் நெறி தவறிச் செல்கின்றவன், எப்போதும் அழியாமல் நிலைநிற்கும் பழியை அடைவான்.",en:"He who thinks lightly of going into the wife of another acquires guilt that will abide with him imperishably and for ever."}, couplet_en:"Mere trifle saying thus, invades the home, so he ensures A gain of guilt that deathless aye endures.", transliteration:"Elidhena Illirappaan Eydhumenj Gnaandrum Viliyaadhu Nirkum Pazhi", tags:{ta:["அடுத்தவன் மனைவி","பழி","குற்றம்","அழிவு"],en:["another's wife","guilt","eternal disgrace","sin","conduct"]} },
  { number:146, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:15,ta:"பிறனில் விழையாமை",en:"Not Coveting Another's Wife"}, kural:{line1:"பகைபாவம் அச்சம் பழியென நான்கும்",line2:"இகவாவாம் இல்லிறப்பான் கண்."}, meaning:{ta:"பகை பாவம் அச்சம் பழி என்னும் இந்நான்கு குற்றங்களும் பிறன் மனைவியிடத்து நெறி தவறி நடப்பவனிடத்திலிருந்து நீங்காவாம்.",en:"Hatred, sin, fear, disgrace; these four will never leave him who goes in to his neighbour's wife."}, couplet_en:"Who home invades, from him pass nevermore, Hatred and sin, fear, foul disgrace; these four.", transliteration:"Pakaipaavam Achcham Pazhiyena Naankum Ikavaavaam Illirappaan Kan", tags:{ta:["அடுத்தவன் மனைவி","பகை","பாவம்","அச்சம்"],en:["another's wife","enmity","sin","fear","disgrace"]} },
  { number:147, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:15,ta:"பிறனில் விழையாமை",en:"Not Coveting Another's Wife"}, kural:{line1:"அறனியலான் இல்வாழ்வான் என்பான் பிறனியலாள்",line2:"பெண்மை நயவா தவன்."}, meaning:{ta:"அறத்தின் இயல்போடு பொருந்தி இல்வாழ்க்கை வாழ்பவன், பிறனுக்கு உரிமையானவளின் பெண் தன்மையை விரும்பாதவனே.",en:"He who desires not the womanhood of her who should walk according to the will of another will be praised as a virtuous house-holder."}, couplet_en:"Who sees the wife, another's own, with no desiring eye In sure domestic bliss he dwelleth ever virtuously.", transliteration:"Araniyalaan Ilvaazhvaan Enpaan Piraniyalaal Penmai Nayavaa Thavan", tags:{ta:["இல்வாழ்வு","கற்பு","அறம்","பிறன் மனைவி"],en:["householder","chastity","virtue","another's wife","ethics"]} },
  { number:148, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:15,ta:"பிறனில் விழையாமை",en:"Not Coveting Another's Wife"}, kural:{line1:"பிறன்மனை நோக்காத பேராண்மை சான்றோர்க்கு",line2:"அறனொன்றோ ஆன்ற வொழுக்கு."}, meaning:{ta:"பிறனுடைய மனைவியை விரும்பி நோக்காத பெரிய ஆண்மை, சான்றோர்க்கு அறம் மட்டும் அன்று; நிறைந்த ஒழுக்கமுமாகும்.",en:"That noble manliness which looks not at the wife of another is the virtue and dignity of the great."}, couplet_en:"Manly excellence, that looks not on another's wife, Is not virtue merely, tis full propriety of life.", transliteration:"Piranmanai Nokkaadha Peraanmai Saandrorkku Aranondro Aandra Vozhukku", tags:{ta:["ஆண்மை","கற்பு","சான்றோர்","ஒழுக்கம்"],en:["manliness","chastity","virtue","decorum","great men"]} },
  { number:149, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:15,ta:"பிறனில் விழையாமை",en:"Not Coveting Another's Wife"}, kural:{line1:"நலக்குரியார் யாரெனின் நாமநீர் வைப்பின்",line2:"பிறர்க்குரியாள் தோள்தோயா தார்."}, meaning:{ta:"கடல் சூழ்ந்த உலகத்தில் நன்மைக்கு உரியவர் யார் என்றால் பிறனுக்கு உரிமையானவளின் தோளைப் பொருந்தாதவரே ஆவர்.",en:"Is it asked who are those who shall obtain good in this world surrounded by the terror-producing sea? Those who touch not the shoulder of her who belongs to another."}, couplet_en:"Who are good indeed, on earth begirt by ocean's gruesome tide? The men who touch not her that is another's bride.", transliteration:"Nalakkuriyaar Yaarenin Naamaneer Vaippin Pirarkkuriyaal Tholdhoyaa Thaar", tags:{ta:["நன்மை","கற்பு","கடல்","அடுத்தவன் மனைவி"],en:["goodness","chastity","ocean","another's wife","virtue"]} },
  { number:150, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:15,ta:"பிறனில் விழையாமை",en:"Not Coveting Another's Wife"}, kural:{line1:"அறன்வரையான் அல்ல செயினும் பிறன்வரையாள்",line2:"பெண்மை நயவாமை நன்று."}, meaning:{ta:"ஒருவன் அறநெறியில் நிற்காமல் அறமில்லாதவைகளைச் செய்தாலும், பிறனுக்கு உரியவளின் பெண்மையை விரும்பாமல் வாழ்தல் நல்லது.",en:"Though a man perform no virtuous deeds and commit every vice, it will be well if he desire not the womanhood of her who is within the limit of the house of another."}, couplet_en:"Though virtue's bounds he pass, and evil deeds hath wrought; At least, tis good if neighbour's wife he covet not.", transliteration:"Aranvaraiyaan Alla Seyinum Piranvaraiyaal Penmai Nayavaamai Nandru", tags:{ta:["கற்பு","அடுத்தவன் மனைவி","அறம்","நன்மை"],en:["chastity","another's wife","virtue","goodness","minimum"]} },
  { number:151, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:16,ta:"பொறையுடைமை",en:"Patience and Forbearance"}, kural:{line1:"அகழ்வாரைத் தாங்கும் நிலம்போலத் தம்மை",line2:"இகழ்வார்ப் பொறுத்தல் தலை."}, meaning:{ta:"தன்னை வெட்டுவோரையும் விழாமல் தாங்குகின்ற நிலம் போல், தம்மை இகழ்வாரையும் பொறுப்பதே தலையான பண்பாகும்.",en:"To bear with those who revile us, just as the earth bears up those who dig it, is the first of virtues."}, couplet_en:"As earth bears up the men who delve into her breast, To bear with scornful men of virtues is the best.", transliteration:"Akazhvaaraith Thaangum Nilampolath Thammai Ikazhvaarp Poruththal Thalai", tags:{ta:["பொறுமை","நிலம்","இகழ்வு","அறம்"],en:["patience","earth","tolerance","forbearance","virtue"]} },
  { number:152, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:16,ta:"பொறையுடைமை",en:"Patience and Forbearance"}, kural:{line1:"பொறுத்தல் இறப்பினை என்றும் அதனை",line2:"மறத்தல் அதனினும் நன்று."}, meaning:{ta:"வரம்பு கடந்து பிறர் செய்யும் தீங்கை எப்போதும் பொறுக்க வேண்டும்; அத் தீங்கை நினைவிலும் கொள்ளாமல் மறந்து விடுதல் பொறுத்தலை விட நல்லது.",en:"Bear with reproach even when you can retaliate; but to forget it will be still better than that."}, couplet_en:"Forgiving trespasses is good always; Forgetting them hath even higher praise.", transliteration:"Poruththal Irappinai Endrum Adhanai Maraththal Adhaninum Nandru", tags:{ta:["பொறுமை","மன்னிப்பு","மறதி","அறம்"],en:["patience","forgiveness","forget","forbearance","virtue"]} },
  { number:153, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:16,ta:"பொறையுடைமை",en:"Patience and Forbearance"}, kural:{line1:"இன்நம்யுள் இன்மை விருந்தொரால் வன்மையுள்",line2:"வன்மை மடவார்ப் பொறை."}, meaning:{ta:"வறுமையுள் வறுமை, விருந்தினரைப் போற்றாமல் நீக்குதல்; வல்லமையுள் வல்லமை என்பது அறிவிலார் தீங்கு செய்தலைப் பொறுத்தலாகும்.",en:"To neglect hospitality is poverty of poverty. To bear with the ignorant is might of might."}, couplet_en:"The sorest poverty is bidding guest unfed depart; The mightiest might to bear with men of foolish heart.", transliteration:"Inmaiyul Inmai Virundhoraal Vanmaiyul Vanmai Matavaarp Porai", tags:{ta:["பொறுமை","வறுமை","விருந்து","வலிமை"],en:["patience","poverty","hospitality","strength","forbearance"]} },
  { number:154, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:16,ta:"பொறையுடைமை",en:"Patience and Forbearance"}, kural:{line1:"நிறையுடைமை நீங்காமை வேண்டின் பொற்யுடைமை",line2:"போற்றி யொழுகப் படும்."}, meaning:{ta:"சான்றாண்மை நம்மைவிட்டு விலகக்கூடாது என விரும்பினால் பொறுமையைப் பின்பற்றி வாழ வேண்டும்.",en:"If you desire that greatness should never leave, you preserve in your conduct the exercise of patience."}, couplet_en:"Seekst thou honour never tarnished to retain; So must thou patience, guarding evermore, maintain.", transliteration:"Niraiyutaimai Neengaamai Ventin Poraiyutaimai Potri Yozhukap Patum", tags:{ta:["பொறுமை","சிறப்பு","நிறை","கடமை"],en:["patience","integrity","honour","forbearance","virtue"]} },
  { number:155, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:16,ta:"பொறையுடைமை",en:"Patience and Forbearance"}, kural:{line1:"ஒறுத்தாரை ஒன்றாக வையாரே வைப்பர்",line2:"பொறுத்தாரைப் பொன்போற் பொதிந்து."}, meaning:{ta:"தீங்கு செய்தவரைப் பொறுக்காமல் வருத்தினவரை உலகத்தார் ஒரு பொருளாக மதியார்; ஆனால், பொறுத்தவரைப் பொன்போல் மனத்துள் வைத்து மதிப்பர்.",en:"The wise will not at all esteem the resentful. They will esteem the patient just as the gold which they lay up with care."}, couplet_en:"Who wreak their wrath as worthless are despised; Who patiently forbear as gold are prized.", transliteration:"Oruththaarai Ondraaka Vaiyaare Vaippar Poruththaaraip Ponpor Podhindhu", tags:{ta:["பொறுமை","பொன்","சினம்","மதிப்பு"],en:["patience","gold","revenge","esteem","forbearance"]} },
  { number:156, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:16,ta:"பொறையுடைமை",en:"Patience and Forbearance"}, kural:{line1:"ஒறுத்தார்க்கு ஒருநாளை இன்பம் பொறுத்தார்க்குப்",line2:"பொன்றுந் துணையும் புகழ்."}, meaning:{ta:"தீங்கு செய்தவரைப் பொறுக்காமல் வருத்தினவர்க்கு ஒருநாள் இன்பமே; பொறுத்தவர்க்கு உலகம் அழியும் வரைக்கும் புகழ் உண்டு.",en:"The pleasure of the resentful continues for a day. The praise of the patient will continue until the final destruction of the world."}, couplet_en:"Who wreak their wrath have pleasure for a day; Who bear have praise till earth shall pass away.", transliteration:"Oruththaarkku Orunaalai Inpam Poruththaarkkup Pondrun Thunaiyum Pukazh", tags:{ta:["பொறுமை","புகழ்","சினம்","இன்பம்"],en:["patience","fame","revenge","one day","eternal praise"]} },
  { number:157, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:16,ta:"பொறையுடைமை",en:"Patience and Forbearance"}, kural:{line1:"திறனல்ல தற்பிறர் செய்யினும் நோநொந்து",line2:"அறனல்ல செய்யாமை நன்று."}, meaning:{ta:"தகுதி அல்லாதவைகளைத் தனக்குப் பிறர் செய்த போதிலும், அதனால் அவர்க்கு வரும் துன்பத்திற்காக நொந்து, அறம் அல்லாதவைகளைச் செய்யாதிருத்தல் நல்லது.",en:"Though others inflict injuries on you, yet compassionating the evil that will come upon them, it will be well not to do them anything contrary to virtue."}, couplet_en:"Though others work thee ill, thus shalt thou blessing reap; Grieve for their sin, thyself from vicious action keep.", transliteration:"Thiranalla Tharpirar Seyyinum Nonondhu Aranalla Seyyaamai Nandru", tags:{ta:["பொறுமை","கருணை","தீமை","அறம்"],en:["patience","compassion","injury","virtue","forbearance"]} },
  { number:158, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:16,ta:"பொறையுடைமை",en:"Patience and Forbearance"}, kural:{line1:"மிகுதியான் மிக்கவை செய்தாரைத் தாந்தம்",line2:"தகுதியான் வென்று விடல்."}, meaning:{ta:"செருக்கினால் தீங்கானவற்றைச் செய்தவரைத் தாம் தம்முடைய பொறுமைப் பண்பினால் பொறுத்து வென்று விட வேண்டும்.",en:"Let a man by patience overcome those who through pride commit excesses."}, couplet_en:"With overweening pride when men with injuries assail, By thine own righteous dealing shalt thou mightily prevail.", transliteration:"Mikudhiyaan Mikkavai Seydhaaraith Thaandham Thakudhiyaan Vendru Vital", tags:{ta:["பொறுமை","செருக்கு","வெற்றி","அறம்"],en:["patience","pride","victory","forbearance","overcome"]} },
  { number:159, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:16,ta:"பொறையுடைமை",en:"Patience and Forbearance"}, kural:{line1:"துறந்தாரின் தூய்மை உடையர் இறந்தார்வாய்",line2:"இன்னாச்சொல் நோற்கிற் பவர்."}, meaning:{ta:"வரம்பு கடந்து நடப்பவரின் வாயில் பிறக்கும் கொடுஞ்சொற்களைப் பொறுத்துக் கொள்பவர், துறந்தவரைப் போலத் தூய்மையானவர் ஆவர்.",en:"Those who bear with the uncourteous speech of the insolent are as pure as the ascetics."}, couplet_en:"They who transgressors' evil words endure With patience, are as stern ascetics pure.", transliteration:"Thurandhaarin Thooimai Utaiyar Irandhaarvaai Innaachchol Norkir Pavar", tags:{ta:["பொறுமை","தூய்மை","துறவு","கடுஞ்சொல்"],en:["patience","purity","asceticism","harsh words","forbearance"]} },
  { number:160, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:16,ta:"பொறையுடைமை",en:"Patience and Forbearance"}, kural:{line1:"உண்ணாது நோற்பார் பெரியர் பிறர்சொல்லும்",line2:"இன்னாச்சொல் நோற்பாரின் பின்."}, meaning:{ta:"பிறர் சொல்லும் கொடுஞ்சொற்களைப் பொறுப்பவர்க்கு அடுத்த நிலையில்தான் விரதம் காரணமாக உணவைத் தவிர்த்து நோன்பு இருப்பவர் பெரியவர் ஆவார்.",en:"Those who endure abstinence from food are great, next to those who endure the uncourteous speech of others."}, couplet_en:"Though great we deem the men that fast and suffer pain, Who others' bitter words endure, the foremost place obtain.", transliteration:"Unnaadhu Norpaar Periyar Pirarsollum Innaachchol Norpaarin Pin", tags:{ta:["பொறுமை","நோன்பு","கடுஞ்சொல்","பெரியோர்"],en:["patience","fasting","harsh words","greatness","forbearance"]} },
  { number:161, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:17,ta:"அழுக்காறாமை",en:"Not Envying"}, kural:{line1:"ஒழுக்காறாக் கொள்க ஒருவன்தன் நெஞ்சத்து",line2:"அழுக்காறு இலாத இயல்பு."}, meaning:{ta:"ஒருவன் தன் நெஞ்சில் பொறாமை இல்லாமல் வாழும் இயல்பைத் தனக்கு உரிய ஒழுக்க நெறியாகக் கொண்டு போற்ற வேண்டும்.",en:"Let a man esteem that disposition which is free from envy in the same manner as propriety of conduct."}, couplet_en:"As strict decorum's laws, that all men bind, Let each regard unenvying grace of mind.", transliteration:"Ozhukkaaraak Kolka Oruvandhan Nenjaththu Azhukkaaru Ilaadha Iyalpu", tags:{ta:["பொறாமையின்மை","ஒழுக்கம்","இயல்பு","நெஞ்சு"],en:["no envy","decorum","nature","mind","virtue"]} },
  { number:162, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:17,ta:"அழுக்காறாமை",en:"Not Envying"}, kural:{line1:"விழுப்பேற்றின் அஃதொப்பது இல்லையார் மாட்டும்",line2:"அழுக்காற்றின் அன்மை பெறின்."}, meaning:{ta:"யாரிடத்திலும் பொறாமை இல்லாதிருக்கப் பெற்றால், ஒருவன் பெறத்தக்க மேம்பாடான பேறுகளில் அதற்கு ஒப்பானது வேறொன்றும் இல்லை.",en:"Amongst all attainable excellences there is none equal to that of being free from envy towards others."}, couplet_en:"If man can learn to envy none on earth, Tis richest gift, beyond compare its worth.", transliteration:"Vizhuppetrin Aqdhoppadhu Illaiyaar Maattum Azhukkaatrin Anmai Perin", tags:{ta:["பொறாமையின்மை","சிறப்பு","பேறு","நன்மை"],en:["no envy","excellence","gift","blessing","virtue"]} },
  { number:163, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:17,ta:"அழுக்காறாமை",en:"Not Envying"}, kural:{line1:"அறன்ஆக்கம் வேண்டாதான் என்பான் பிறனாக்கம்",line2:"பேணாது அழுக்கறுப் பான்."}, meaning:{ta:"தனக்கு அறமும் ஆக்கமும் விரும்பாதவன் என்று கருதத் தக்கவனே, பிறனுடைய ஆக்கத்தைக் கண்டு மகிழாமல் அதற்காகப் பொறாமைப்படுவான்.",en:"Of him who instead of rejoicing in the wealth of others, envies it, it will be said he neither desires virtue nor wealth."}, couplet_en:"Nor wealth nor virtue does that man desire tis plain, Whom others' wealth delights not, feeling envious pain.", transliteration:"Aranaakkam Ventaadhaan Enpaan Piranaakkam Penaadhu Azhukkarup Paan", tags:{ta:["பொறாமை","அறம்","செல்வம்","மூடம்"],en:["envy","virtue","wealth","foolishness","sin"]} },
  { number:164, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:17,ta:"அழுக்காறாமை",en:"Not Envying"}, kural:{line1:"அழுக்காற்றின் அல்லவை செய்யார் இழுக்காற்றின்",line2:"ஏதம் படுபாக்கு அறிந்து."}, meaning:{ta:"பொறாமைப்படுதலாகிய தவறான நெறியில் துன்பம் ஏற்படுதை அறிந்து, பொறாமை காரணமாக அறமல்லாதவைகளைச் செய்யார் அறிவுடையோர்.",en:"The wise knowing the misery that comes from transgression will not through envy commit unrighteous deeds."}, couplet_en:"The wise through envy break not virtue's laws, Knowing ill-deeds of foul disgrace the cause.", transliteration:"Azhukkaatrin Allavai Seyyaar Izhukkaatrin Edham Patupaakku Arindhu", tags:{ta:["பொறாமை","அறிவுடையோர்","தீமை","நீதி"],en:["envy","wise men","sin","unrighteous","virtue"]} },
  { number:165, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:17,ta:"அழுக்காறாமை",en:"Not Envying"}, kural:{line1:"அழுக்காறு உடையார்க்கு அதுசாலும் ஒன்னார்",line2:"வழுக்காயும் கேடீன் பது."}, meaning:{ta:"பொறாமை உடையவர்க்கு வேறு பகை வேண்டா. அஃது ஒன்றே போதும், பகைவர் தீங்கு செய்யத் தவறினாலும் தவறாது கேட்டைத் தருவது அது.",en:"To those who cherish envy that is enough. Though free from enemies that envy will bring destruction."}, couplet_en:"Envy they have within! Enough to seat their fate! Though foemen fail, envy can ruin consummate.", transliteration:"Azhukkaaru Utaiyaarkku Adhusaalum Onnaar Vazhukkaayum Keteen Padhu", tags:{ta:["பொறாமை","அழிவு","பகை","தீமை"],en:["envy","ruin","enemy","destruction","self-destruction"]} },
  { number:166, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:17,ta:"அழுக்காறாமை",en:"Not Envying"}, kural:{line1:"கொடுப்பது அழுக்கறுப்பான் சுற்றம் உடுப்பதூஉம்",line2:"உண்பதூஉம் இன்றிக் கெடும்."}, meaning:{ta:"பிறர்க்கு உதவியாகக் கொடுக்கப்படும் பொருளைக் கண்டு பொறாமைப்படுகின்றவனுடைய சுற்றம், உடையும் உணவும் இல்லாமல் கெடும்.",en:"He who is envious at a gift made to another will with his relations utterly perish destitute of food and raiment."}, couplet_en:"Who scans good gifts to others given with envious eye, His kin, with none to clothe or feed them, surely die.", transliteration:"Kotuppadhu Azhukkaruppaan Sutram Utuppadhooum Unpadhooum Indrik Ketum", tags:{ta:["பொறாமை","குடும்பம்","அழிவு","கொடை"],en:["envy","family","ruin","charity","food"]} },
  { number:167, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:17,ta:"அழுக்காறாமை",en:"Not Envying"}, kural:{line1:"அவ்வித்து அழுக்காறு உடையானைச் செய்யவள்",line2:"தவ்வையைக் காட்டி விடும்."}, meaning:{ta:"பொறாமை உடையவனைத் திருமகள் கண்டு பொறாமைப்பட்டுத் தன் தமக்கைக்கு அவனைக் காட்டி நீங்கி விடுவாள்.",en:"Lakshmi envying the prosperity of the envious man will depart and introduce him to her sister."}, couplet_en:"From envious man good fortune's goddess turns away, Grudging him good, and points him out misfortune's prey.", transliteration:"Avviththu Azhukkaaru Utaiyaanaich Cheyyaval Thavvaiyaik Kaatti Vitum", tags:{ta:["பொறாமை","திருமகள்","மூதேவி","செல்வம்"],en:["envy","lakshmi","misfortune","wealth","fortune leaves"]} },
  { number:168, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:17,ta:"அழுக்காறாமை",en:"Not Envying"}, kural:{line1:"அழுக்காறு எனஒரு பாவி திருச்செற்றுத்",line2:"தீயுழி உய்த்து விடும்."}, meaning:{ta:"பொறாமை என்று கூறப்படும் ஒப்பற்ற பாவி, ஒருவனுடைய செல்வத்தைக் கெடுத்துத் தீய வழியில் அவனைச் செலுத்தி விடும்.",en:"Envy will destroy a man's wealth in this world and drive him into the pit of fire in the world to come."}, couplet_en:"Envy, embodied ill, incomparable bane, Good fortune slays, and soul consigns to fiery pain.", transliteration:"Azhukkaaru Enaoru Paavi Thiruchchetruth Theeyuzhi Uyththu Vitum", tags:{ta:["பொறாமை","நரகம்","செல்வம்","அழிவு"],en:["envy","hell","wealth","destruction","sin"]} },
  { number:169, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:17,ta:"அழுக்காறாமை",en:"Not Envying"}, kural:{line1:"அவ்விய நெஞ்சத்தான் ஆக்கமும் செவ்வியான்",line2:"கேடும் நினைக்கப் படும்."}, meaning:{ta:"பொறாமை பொருந்திய நெஞ்சத்தானுடைய ஆக்கமும், பொறாமை இல்லாத நல்லவனுடைய கேடும் ஆராயத் தக்கவை.",en:"The wealth of a man of envious mind and the poverty of the righteous will be pondered."}, couplet_en:"To men of envious heart, when comes increase of joy, Or loss to blameless men, the why will thoughtful hearts employ.", transliteration:"Avviya Nenjaththaan Aakkamum Sevviyaan Ketum Ninaikkap Patum", tags:{ta:["பொறாமை","ஆக்கம்","கேடு","நல்லோர்"],en:["envy","prosperity","loss","righteous","wonder"]} },
  { number:170, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:17,ta:"அழுக்காறாமை",en:"Not Envying"}, kural:{line1:"அழுக்கற்று அகன்றாரும் இல்லை அஃதுஇல்லார்",line2:"பெருக்கத்தில் தீர்ந்தாரும் இல்."}, meaning:{ta:"பொறாமைப்பட்டுப் பெருமையுற்றவரும் உலகத்தில் இல்லை; பொறாமை இல்லாதவராய் மேம்பாட்டிலிருந்து நீங்கியவரும் இல்லை.",en:"Never have the envious become great; never have those who are free from envy been without greatness."}, couplet_en:"No envious men to large and full felicity attain; No men from envy free have failed a sure increase to gain.", transliteration:"Azhukkatru Akandraarum Illai Aqdhuillaar Perukkaththil Theerndhaarum Il", tags:{ta:["பொறாமை","பெருமை","மேன்மை","உண்மை"],en:["envy","greatness","prosperity","truth","law of life"]} },
  { number:171, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:18,ta:"வெஃகாமை",en:"Not Coveting"}, kural:{line1:"நடுவின்றி நன்பொருள் வெஃகின் குடிபொன்றிக்",line2:"குற்றமும் ஆங்கே தரும்."}, meaning:{ta:"நடுவுநிலைமை இல்லாமல் பிறர்க்குரிய நல்ல பொருளை ஒருவன் கவர விரும்பினால் அவனுடைய குடியும் கெட்டுக் குற்றமும் அப்போழுதே வந்து சேரும்.",en:"If a man departing from equity covet the property of others, at that very time will his family be destroyed and guilt be incurred."}, couplet_en:"With soul unjust to covet others' well-earned store, Brings ruin to the home, to evil opes the door.", transliteration:"Natuvindri Nanporul Veqkin Kutipondrik Kutramum Aange Tharum", tags:{ta:["பேராசை","நடுவுநிலை","குடும்பம்","குற்றம்"],en:["covetousness","injustice","family ruin","guilt","greed"]} },
  { number:172, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:18,ta:"வெஃகாமை",en:"Not Coveting"}, kural:{line1:"படுபயன் வெஃகிப் பழிப்படுவ செய்யார்",line2:"நடுவன்மை நாணு பவர்."}, meaning:{ta:"நடுவுநிலைமை அல்லாதவற்றைக் கண்டு நாணி ஒதுங்குகின்றவர், பிறர் பொருளைக் கவர்வதால் வரும் பயனை விரும்பிப் பழியான செயல்களைச் செய்யார்.",en:"Those who blush at the want of equity will not commit disgraceful acts through desire of the profit that may be gained."}, couplet_en:"Through lust of gain, no deeds that retribution bring, Do they, who shrink with shame from every unjust thing.", transliteration:"Patupayan Veqkip Pazhippatuva Seyyaar Natuvanmai Naanu Pavar", tags:{ta:["பேராசை","நாணம்","நடுவுநிலை","அறம்"],en:["covetousness","shame","impartiality","disgrace","virtue"]} },
  { number:173, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:18,ta:"வெஃகாமை",en:"Not Coveting"}, kural:{line1:"சிற்றின்பம் வெஃகி அறனல்ல செய்யாரே",line2:"மற்றின்பம் வேண்டு பவர்."}, meaning:{ta:"அறநெறியால் பெறும் இன்பத்தை விரும்புகின்றவர், நிலையில்லாத சிறிய இன்பத்தை விரும்பி அறம் அல்லாதவற்றைச் செய்யார்.",en:"Those who desire the higher pleasures of heaven will not act unjustly through desire of the trifling joy."}, couplet_en:"No deeds of ill, misled by base desire, Do they, whose souls to other joys aspire.", transliteration:"Sitrinpam Veqki Aranalla Seyyaare Matrinpam Ventu Pavar", tags:{ta:["பேராசை","சிற்றின்பம்","அறம்","நிலையான இன்பம்"],en:["covetousness","fleeting pleasure","virtue","spiritual joy","greed"]} },
  { number:174, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:18,ta:"வெஃகாமை",en:"Not Coveting"}, kural:{line1:"இலமென்று வெஃகுதல் செய்யார் புலம்வென்ற",line2:"புன்மையில் காட்சி யவர்."}, meaning:{ta:"ஐம்புலன்களையும் வென்ற குற்றமில்லாத அறிவை உடையவர், யாம் வறுமை அடைந்தோம் என்று எண்ணியும் பிறர் பொருளை விரும்பார்.",en:"The wise who have conquered their senses and are free from crime, will not covet the things of others, with the thought we are destitute."}, couplet_en:"Men who have conquered sense, with sight from sordid vision freed, Desire not other's goods, e'en in the hour of sorest need.", transliteration:"Ilamendru Veqkudhal Seyyaar Pulamvendra Punmaiyil Kaatchi Yavar", tags:{ta:["பேராசை","புலன்கள்","வறுமை","ஞானம்"],en:["covetousness","senses","poverty","wisdom","virtue"]} },
  { number:175, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:18,ta:"வெஃகாமை",en:"Not Coveting"}, kural:{line1:"அஃகி அகன்ற அறிவென்னாம் யார்மாட்டும்",line2:"வெஃகி வெறிய செயின்."}, meaning:{ta:"யாரிடத்திலும் பொருளைக் கவர விரும்பிப் பொருந்தாதவற்றைச் செய்தால், நுட்பமானதாய் விரிவுடையதாய் வளர்ந்த அறிவால் பயன் என்ன?",en:"What is the advantage of extensive and accurate knowledge if a man through covetousness acts senselessly towards all?"}, couplet_en:"What gain, though lore refined of amplest reach he learn, His acts towards all mankind if covetous desire to folly turn.", transliteration:"Aqki Akandra Arivennaam Yaarmaattum Veqki Veriya Seyin", tags:{ta:["பேராசை","அறிவு","மூடம்","நன்மை"],en:["covetousness","knowledge","folly","greed","wisdom"]} },
  { number:176, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:18,ta:"வெஃகாமை",en:"Not Coveting"}, kural:{line1:"அருள்வெஃகி ஆற்றின்கண் நின்றான் பொருள்வெஃகிப்",line2:"பொல்லாத சூழக் கெடும்."}, meaning:{ta:"அருளை விரும்பி அறநெறியில் நின்றவன், பிறனுடைய பொருளை விரும்பிப் பொல்லாத குற்றங்களை எண்ணினால் கெடுவான்.",en:"If he who through desire of the virtue of kindness abides in the domestic state covet the property of others and think of evil methods to obtain it, he will perish."}, couplet_en:"Though, grace desiring, he in virtue's way stand strong, He's lost who wealth desires, and ponders deeds of wrong.", transliteration:"Arulveqki Aatrinkan Nindraan Porulveqkip Pollaadha Soozhak Ketum", tags:{ta:["பேராசை","அருள்","அழிவு","அறம்"],en:["covetousness","grace","ruin","virtue","greed"]} },
  { number:177, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:18,ta:"வெஃகாமை",en:"Not Coveting"}, kural:{line1:"வேண்டற்க வெஃகியாம் ஆக்கம் விளைவயின்",line2:"மாண்டற் கரிதாம் பயன்."}, meaning:{ta:"பிறர் பொருளைக் கவர விரும்புவதால் ஆகும் ஆக்கத்தை விரும்பாதிருக்க வேண்டும்; அது பயன் விளைவிக்கும்போது அப்பயன் நன்மையாவது அரிதாகும்.",en:"Desire not the gain of covetousness. In the enjoyment of its fruits there is no glory."}, couplet_en:"Seek not increase by greed of gain acquired; That fruit matured yields never good desired.", transliteration:"Ventarka Veqkiyaam Aakkam Vilaivayin Maantar Karidhaam Payan", tags:{ta:["பேராசை","ஆக்கம்","பயன்","அழிவு"],en:["covetousness","gain","fruit","inglorious","greed"]} },
  { number:178, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:18,ta:"வெஃகாமை",en:"Not Coveting"}, kural:{line1:"அஃகாமை செல்வத்திற்கு யாதெனின் வெஃகாமை",line2:"வேண்டும் பிறன்கைப் பொருள்."}, meaning:{ta:"ஒருவனுடைய செல்வத்திற்குக் குறைவு நேராதிருக்க வழி எது என்றால், அவன் பிறனுடைய கைப்பொருளை விரும்பாதிருத்தலாகும்.",en:"If it is weighed, what is the indestructibility of wealth, it is freedom from covetousness."}, couplet_en:"What saves prosperity from swift decline? Absence of lust to make another's cherished riches thine.", transliteration:"Aqkaamai Selvaththirku Yaadhenin Veqkaamai Ventum Pirankaip Porul", tags:{ta:["பேராசை","செல்வம்","பாதுகாப்பு","அறம்"],en:["covetousness","wealth","protection","another's property","greed"]} },
  { number:179, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:18,ta:"வெஃகாமை",en:"Not Coveting"}, kural:{line1:"அறனறிந்து வெஃகா அறிவுடையார்ச் சேரும்",line2:"திறன்அறிந் தாங்கே திரு."}, meaning:{ta:"அறம் இஃது என்று அறிந்து பிறர் பொருளை விரும்பாத அறிவுடையாரைத் திருமகள் தான் சேரும் திறன் அறிந்து அதற்கு ஏற்றவாறு சேர்வாள்.",en:"Lakshmi, knowing the manner in which she may approach, will immediately come to those wise men who, knowing that it is virtue, covet not the property of others."}, couplet_en:"Good fortune draws anigh in helpful time of need, To him who, schooled in virtue, guards his soul from greed.", transliteration:"Aranarindhu Veqkaa Arivutaiyaarch Cherum Thiranarin Thaange Thiru", tags:{ta:["பேராசையின்மை","திருமகள்","அறம்","செல்வம்"],en:["no covetousness","lakshmi","virtue","wealth","fortune"]} },
  { number:180, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:18,ta:"வெஃகாமை",en:"Not Coveting"}, kural:{line1:"இறலீனும் எண்ணாது வெஃகின் விறல்ஈனும்",line2:"வேண்டாமை என்னுஞ் செருக்கு."}, meaning:{ta:"விளைவை எண்ணாமல் பிறர் பொருளை விரும்பினால் அஃது அழிவைத் தரும்; அப்பொருளை விரும்பாமல் வாழும் பெருமை வெற்றியைத் தரும்.",en:"To covet the wealth of another regardless of consequences will bring destruction. That greatness of mind which covets not will give victory."}, couplet_en:"From thoughtless lust of other's goods springs fatal ill, Greatness of soul that covets not shall triumph still.", transliteration:"Iraleenum Ennaadhu Veqkin Viraleenum Ventaamai Ennunj Cherukku", tags:{ta:["பேராசை","வெற்றி","அழிவு","பெருமை"],en:["covetousness","victory","destruction","greatness","triumph"]} },
  { number:181, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:19,ta:"புறங்கூறாமை",en:"Not Backbiting"}, kural:{line1:"அறங்கூறான் அல்ல செயினும் ஒருவன்",line2:"புறங்கூறான் என்றல் இனிது."}, meaning:{ta:"ஒருவன் அறத்தைப் போற்றிக் கூறாதவனாய் அறமல்லாதவற்றைச் செய்தாலும், மற்றவனைப் பற்றிப் புறங்கூறாமல் இருக்கிறான் என்று சொல்லப்படுதல் நல்லது.",en:"Though one do not even speak of virtue and live in sin, it will be well if it be said of him he does not backbite."}, couplet_en:"Though virtuous words his lips speak not, and all his deeds are ill. If neighbour he defame not, there's good within him still.", transliteration:"Arangooraan Alla Seyinum Oruvan Purangooraan Endral Inidhu", tags:{ta:["புறங்கூறல்","அறம்","நல்லது","பழி"],en:["backbiting","virtue","goodness","slander","conduct"]} },
  { number:182, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:19,ta:"புறங்கூறாமை",en:"Not Backbiting"}, kural:{line1:"அறனழீஇ அல்லவை செய்தலின் தீதே",line2:"புறனழீஇப் பொய்த்து நகை."}, meaning:{ta:"அறத்தை அழித்துப் பேசி அறமல்லாதவைகளைச் செய்வதை விட, ஒருவன் இல்லாதவிடத்தில் அவனைப் பழித்துப் பேசி நேரில் பொய்யாக முகமலர்ந்து பேசுதல் தீமையாகும்.",en:"To smile deceitfully in another's presence after having reviled him behind his back is a greater evil than the commission of every other sin."}, couplet_en:"Than he who virtue scorns, and evil deeds performs, more vile, Is he that slanders friend, then meets him with false smile.", transliteration:"Aranazheei Allavai Seydhalin Theedhe Puranazheeip Poiththu Nakai", tags:{ta:["புறங்கூறல்","பொய்","நட்பு","துரோகம்"],en:["backbiting","deceit","false smile","slander","hypocrisy"]} },
  { number:183, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:19,ta:"புறங்கூறாமை",en:"Not Backbiting"}, kural:{line1:"புறங்கூறிப் பொய்த்துயிர் வாழ்தலின் சாதல்",line2:"அறங்கூற்றும் ஆக்கத் தரும்."}, meaning:{ta:"புறங்கூறிப் பொய்யாக நடந்து உயிர் வாழ்தலை விட, அவ்வாறு செய்யாமல் வறுமையுற்று இறந்து விடுதல், அறநூல்கள் சொல்லும் ஆக்கத்தைத் தரும்.",en:"Death rather than life will confer upon the deceitful backbiter the profit which the treatises on virtue point out."}, couplet_en:"Tis greater gain of virtuous good for man to die, Than live to slander absent friend, and falsely praise when nigh.", transliteration:"Purangoorip Poiththuyir Vaazhdhalin Saadhal Arangootrum Aakkath Tharum", tags:{ta:["புறங்கூறல்","மரணம்","வாழ்வு","அறம்"],en:["backbiting","death","virtue","slander","honesty"]} },
  { number:184, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:19,ta:"புறங்கூறாமை",en:"Not Backbiting"}, kural:{line1:"கண்ணின்று கண்ணறச் சொல்லினும் சொல்லற்க",line2:"முன்னின்று பின்நோக்காச் சொல்."}, meaning:{ta:"எதிரே நின்று கண்ணோட்டம் இல்லாமல் கடுமையாகச் சொன்னாலும் சொல்லலாம்; நேரில் இல்லாதபோது பின் விளைவை ஆராயாத சொல்லைச் சொல்லக்கூடாது.",en:"Though you speak without kindness before another's face, speak not in his absence words which regard not the evil subsequently resulting from it."}, couplet_en:"In presence though unkindly words you speak, say not In absence words whose ill result exceeds your thought.", transliteration:"Kannindru Kannarach Chollinum Sollarka Munnindru Pinnokkaach Chol", tags:{ta:["புறங்கூறல்","சொல்","பின்விளைவு","அறம்"],en:["backbiting","speech","consequence","absent friend","conduct"]} },
  { number:185, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:19,ta:"புறங்கூறாமை",en:"Not Backbiting"}, kural:{line1:"அறஞ்சொல்லும் நெஞ்சத்தான் அன்மை புறஞ்சொல்லும்",line2:"புன்மையாற் காணப் படும்."}, meaning:{ta:"அறத்தை நல்லதென்று போற்றும் நெஞ்சம் இல்லாததன்மை, ஒருவன் மற்றவனைப் பற்றிப் புறங்கூறுகின்ற சிறுமையால் காணப்படும்.",en:"The emptiness of that man's mind who merely praises virtue will be seen from the meanness of reviling another behind his back."}, couplet_en:"The slanderous meanness that an absent friend defames, This man in words owns virtue, not in heart, proclaims.", transliteration:"Aranjollum Nenjaththaan Anmai Puranjollum Punmaiyaar Kaanap Patum", tags:{ta:["புறங்கூறல்","நெஞ்சு","அறம்","வெற்றுவார்த்தை"],en:["backbiting","heart","virtue","empty praise","hypocrisy"]} },
  { number:186, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:19,ta:"புறங்கூறாமை",en:"Not Backbiting"}, kural:{line1:"பிறன்பழி கூறுவான் தன்பழி யுள்ளும்",line2:"திறன்தெரிந்து கூறப் படும்."}, meaning:{ta:"மற்றவனைப் பற்றிப் புறங்கூறுகின்றவன், அவனுடைய பழிகள் பலவற்றிலும் நோகத்தக்கவை ஆராய்ந்து கூறிப் பிறரால் பழிக்கப்படுவான்.",en:"The character of the faults of that man who publishes abroad the faults of others will be sought out and published."}, couplet_en:"Who on his neighbours' sins delights to dwell, The story of his sins, culled out with care, the world will tell.", transliteration:"Piranpazhi Kooruvaan Thanpazhi Yullum Thirandherindhu Koorap Patum", tags:{ta:["புறங்கூறல்","பழி","சமத்துவம்","நீதி"],en:["backbiting","fault","reciprocal","justice","slander"]} },
  { number:187, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:19,ta:"புறங்கூறாமை",en:"Not Backbiting"}, kural:{line1:"பகச்சொல்லிக் கேளிர்ப் பிரிப்பர் நகச்சொல்லி",line2:"நட்பாடல் தேற்றா தவர்."}, meaning:{ta:"மகிழும்படியாகப் பேசி நட்புக் கொள்ளுதல் நன்மை என்று தெளியாதவர் தம்மை விட்டு நீங்கும்படியாகப் புறம் கூறி நண்பரையும் பிரித்து விடுவர்.",en:"Those who know not to live in friendship with amusing conversation will by back-biting estrange even their relatives."}, couplet_en:"With friendly art who know not pleasant words to say, Speak words that sever hearts, and drive choice friends away.", transliteration:"Pakachchollik Kelirp Pirippar Nakachcholli Natpaatal Thetraa Thavar", tags:{ta:["புறங்கூறல்","நட்பு","பிரிவு","சொல்"],en:["backbiting","friendship","estrange","slander","speech"]} },
  { number:188, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:19,ta:"புறங்கூறாமை",en:"Not Backbiting"}, kural:{line1:"துன்னியார் குற்றமும் தூற்றும் மரபினார்",line2:"என்னைகொல் ஏதிலார் மாட்டு."}, meaning:{ta:"நெருங்கிப் பழகியவரின் குற்றத்தையும் புறங்கூறித் தூற்றும் இயல்புடையவர், பழகாத அயலாரிடத்து என்ன செய்வாரோ?",en:"What will those not do to strangers whose nature leads them to publish abroad the faults of their intimate friends?"}, couplet_en:"Whose nature bids them faults of closest friends proclaim What mercy will they show to other men's good name.", transliteration:"Thunniyaar Kutramum Thootrum Marapinaar Ennaikol Edhilaar Maattu", tags:{ta:["புறங்கூறல்","நட்பு","அயலார்","நம்பிக்கை"],en:["backbiting","friends","strangers","trust","slander"]} },
  { number:189, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:19,ta:"புறங்கூறாமை",en:"Not Backbiting"}, kural:{line1:"அறன்நோக்கி ஆற்றுங்கொல் வையம் புறன்நோக்கிப்",line2:"புன்சொல் உரைப்பான் பொறை."}, meaning:{ta:"ஒருவர் நேரில் இல்லாதது கண்டு பழிச்சொல் கூறுவோனுடைய உடல் பாரத்தை, இவனையும் சுமப்பதே எனக்கு அறம் என்று கருதி நிலம் சுமக்கின்றதோ?",en:"The world through charity supports the weight of those who reproach others observing their absence."}, couplet_en:"Tis charity, I ween, that makes the earth sustain their load. Who, neighbours' absence watching, tales or slander tell abroad.", transliteration:"Arannokki Aatrungol Vaiyam Purannokkip Punsol Uraippaan Porai", tags:{ta:["புறங்கூறல்","நிலம்","அறம்","பாரம்"],en:["backbiting","earth","charity","burden","slander"]} },
  { number:190, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:19,ta:"புறங்கூறாமை",en:"Not Backbiting"}, kural:{line1:"ஏதிலார் குற்றம்போல் தங்குற்றங் காண்கிற்பின்",line2:"தீதுண்டோ மன்னும் உயிர்க்கு."}, meaning:{ta:"அயலாருடைய குற்றத்தைக் காண்பது போல் தம் குற்றத்தையும் காண வல்லவரானால், நிலைபெற்ற உயிர் வாழ்க்கைக்குத் துன்பம் உண்டோ?",en:"If they observed their own faults as they observe the faults of others, would any evil happen to men?"}, couplet_en:"If each his own, as neighbours' faults would scan, Could any evil hap to living man.", transliteration:"Edhilaar Kutrampol Thangutrang Kaankirpin Theedhunto Mannum Uyirkku", tags:{ta:["குற்றம்","சுயம் அறிதல்","பிறர் குற்றம்","அறம்"],en:["self-awareness","faults","others' faults","virtue","introspection"]} },
  { number:191, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:20,ta:"பயனில சொல்லாமை",en:"Against Vain Speaking"}, kural:{line1:"பல்லார் முனியப் பயனில சொல்லுவான்",line2:"எல்லாரும் எள்ளப் படும்."}, meaning:{ta:"கேட்டவர் பலரும் வெறுக்கும் படியாகப் பயனில்லாத சொற்களைச் சொல்லுகின்றவன், எல்லாராலும் இகழப்படுவான்.",en:"He who to the disgust of many speaks useless things will be despised by all."}, couplet_en:"Words without sense, while chafe the wise, Who babbles, him will all despise.", transliteration:"Pallaar Muniyap Payanila Solluvaan Ellaarum Ellap Patum", tags:{ta:["வீண்பேச்சு","இகழ்வு","பயனின்மை","சொல்"],en:["vain speech","despised","useless words","conduct","wisdom"]} },
  { number:192, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:20,ta:"பயனில சொல்லாமை",en:"Against Vain Speaking"}, kural:{line1:"பயனில பல்லார்முன் சொல்லல் நயனில",line2:"நட்டார்கண் செய்தலிற் றீது."}, meaning:{ta:"பலர் முன்னே பயனில்லாத சொற்களைச் சொல்லுதல், நண்பரிடத்தில் அறம் இல்லா செயல்களைச் செய்தலை விடத் தீமையானதாகும்.",en:"To speak useless things in the presence of many is a greater evil than to do unkind things towards friends."}, couplet_en:"Words without sense, where many wise men hear, to pour. Than deeds to friends ungracious done offendeth more.", transliteration:"Payanila Pallaarmun Sollal Nayanila Nattaarkan Seydhalir Reedhu", tags:{ta:["வீண்பேச்சு","நட்பு","தீமை","சொல்"],en:["vain speech","friends","harm","assembly","conduct"]} },
  { number:193, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:20,ta:"பயனில சொல்லாமை",en:"Against Vain Speaking"}, kural:{line1:"நயனிலன் என்பது சொல்லும் பயனில",line2:"பாரித் துரைக்கும் உரை."}, meaning:{ta:"ஒருவன் பயனில்லா பொருள்களைப் பற்றி விரிவாகச் சொல்லும் சொற்கள், அவன் அறம் இல்லாதவன் என்பதை அறிவிக்கும்.",en:"That conversation in which a man utters forth useless things will say of him he is without virtue."}, couplet_en:"Diffusive speech of useless words proclaims A man who never righteous wisdom gains.", transliteration:"Nayanilan Enpadhu Sollum Payanila Paarith Thuraikkum Urai", tags:{ta:["வீண்பேச்சு","அறமின்மை","தகுதி","சொல்"],en:["vain speech","no virtue","character","words reveal","conduct"]} },
  { number:194, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:20,ta:"பயனில சொல்லாமை",en:"Against Vain Speaking"}, kural:{line1:"நயன்சாரா நன்மையின் நீக்கும் பயன்சாராப்",line2:"பண்பில்சொல் பல்லா ரகத்து."}, meaning:{ta:"பயனோடு பொருந்தாத பண்பு இல்லாத சொற்களைப் பலரிடத்தும் சொல்லுதல், அறத்தோடு பொருந்தாமல் நன்மையிலிருந்து நீங்கச் செய்யும்.",en:"The words devoid of profit or pleasure which a man speaks will, being inconsistent with virtue, remove him from goodness."}, couplet_en:"Unmeaning, worthless words, said to the multitude, To none delight afford, and sever men from good.", transliteration:"Nayansaaraa Nanmaiyin Neekkum Payansaaraap Panpilsol Pallaa Rakaththu", tags:{ta:["வீண்பேச்சு","நன்மையின்மை","பண்பு","சொல்"],en:["vain speech","worthless words","goodness","conduct","virtue"]} },
  { number:195, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:20,ta:"பயனில சொல்லாமை",en:"Against Vain Speaking"}, kural:{line1:"சீர்மை சிறப்பொடு நீங்கும் பயனில",line2:"நீர்மை யுடையார் சொலின்."}, meaning:{ta:"பயனில்லாத சொற்களை நல்ல பண்பு உடையவர் சொல்லுவாரானால், அவனுடைய மேம்பாடு அவர்க்குரிய மதிப்போடு நீங்கிவிடும்.",en:"If the good speak vain words their eminence and excellence will leave them."}, couplet_en:"Gone are both fame and boasted excellence, When men of worth speak of words devoid of sense.", transliteration:"Seermai Sirappotu Neengum Payanila Neermai Yutaiyaar Solin", tags:{ta:["வீண்பேச்சு","பண்பாளர்","புகழ்","இழப்பு"],en:["vain speech","good men","fame lost","excellence","conduct"]} },
  { number:196, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:20,ta:"பயனில சொல்லாமை",en:"Against Vain Speaking"}, kural:{line1:"பயனில் சொல் பராட்டு வானை மகன்எனல்",line2:"மக்கட் பதடி யெனல்."}, meaning:{ta:"பயனற்ற சொற்களையே பலகாலமும் சொல்லுகின்ற ஒருவனை மனிதன் என்று சொல்லக்கூடாது, மனிதருள் பதர் என்று சொல்லவேண்டும்.",en:"Call not him a man who parades forth his empty words. Call him the chaff of men."}, couplet_en:"Who makes display of idle words' inanity, Call him not man, chaff of humanity.", transliteration:"Payanil Sol Paaraattu Vaanai Makanenal Makkat Padhati Yenal", tags:{ta:["வீண்பேச்சு","பதர்","மனிதன்","சொல்"],en:["vain speech","chaff","not a man","empty words","conduct"]} },
  { number:197, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:20,ta:"பயனில சொல்லாமை",en:"Against Vain Speaking"}, kural:{line1:"நயனில சொல்லினுஞ் சொல்லுக சான்றோர்",line2:"பயனில சொல்லாமை நன்று."}, meaning:{ta:"அறம் இல்லாதவற்றைச் சொன்னாலும் சொல்லலாம், சான்றோர் பயன் இல்லாத சொற்களைச் சொல்லாமல் இருத்தல் நன்மையாகும்.",en:"Let the wise if they will, speak things without excellence; it will be well for them not to speak useless things."}, couplet_en:"Let those who list speak things that no delight afford, Tis good for men of worth to speak no idle word.", transliteration:"Nayanila Sollinunj Cholluka Saandror Payanila Sollaamai Nandru", tags:{ta:["வீண்பேச்சு","சான்றோர்","நன்மை","சொல்"],en:["vain speech","wise men","goodness","virtue","silence"]} },
  { number:198, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:20,ta:"பயனில சொல்லாமை",en:"Against Vain Speaking"}, kural:{line1:"அரும்பயன் ஆயும் அறிவினார் சொல்லார்",line2:"பெரும்பயன் இல்லாத சொல்."}, meaning:{ta:"அருமையான பயன்களை ஆராயவல்ல அறிவை உடைய அறிஞர், மிக்க பயன் இல்லாத சொற்களை ஒருபோதும் சொல்லமாட்டார்.",en:"The wise who seek after rare pleasures will not speak words that have not much weight in them."}, couplet_en:"The wise who weigh the worth of every utterance, Speak none but words of deep significance.", transliteration:"Arumpayan Aayum Arivinaar Sollaar Perumpayan Illaadha Sol", tags:{ta:["வீண்பேச்சு","அறிவுடையோர்","அரும்பயன்","சொல்"],en:["vain speech","wise men","rare benefit","meaningful words","silence"]} },
  { number:199, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:20,ta:"பயனில சொல்லாமை",en:"Against Vain Speaking"}, kural:{line1:"பொருள்தீர்ந்த பொச்சாந்துஞ் சொல்லார் மருள்தீர்ந்த",line2:"மாசறு காட்சி யவர்."}, meaning:{ta:"மயக்கத்திலிருந்து தெளிந்த மாசற்ற அறிவை உடையவர், பயன் நீங்கிய சொற்களை ஒருகால் மறந்தும் சொல்லமாட்டார்.",en:"Those wise men who are without faults and are freed from ignorance will not even forgetfully speak things that profit not."}, couplet_en:"The men of vision pure, from wildering folly free, Not e'en in thoughtless hour, speak words of vanity.", transliteration:"Poruldheerndha Pochchaandhunj Chollaar Maruldheerndha Maasaru Kaatchi Yavar", tags:{ta:["வீண்பேச்சு","தூய அறிவு","மயக்கம்","சொல்"],en:["vain speech","pure wisdom","ignorance free","meaningful","silence"]} },
  { number:200, pal:{ta:"அறத்துப்பால்",en:"Virtue"}, iyal:{ta:"இல்லறவியல்",en:"Domestic Virtue"}, adhigaram:{number:20,ta:"பயனில சொல்லாமை",en:"Against Vain Speaking"}, kural:{line1:"சொல்லுக சொல்லிற் பயனுடைய சொல்லற்க",line2:"சொல்லிற் பயனிலாச் சொல்."}, meaning:{ta:"சொற்களில் பயன் உடைய சொற்களை மட்டுமே சொல்லவேண்டும், பயன் இல்லாதவைகளாகிய சொற்களை சொல்லவே கூடாது.",en:"Speak what is useful, and speak not useless words."}, couplet_en:"If speak you will, speak words that fruit afford, If speak you will, speak never fruitless word.", transliteration:"Solluka Sollir Payanutaiya Sollarka Sollir Payanilaach Chol", tags:{ta:["வீண்பேச்சு","பயனுள்ள சொல்","நன்மை","சொல்"],en:["vain speech","useful words","virtue","speech","wisdom"]} }
];
